function p(t){if(t==null||t==="")return"";const r=parseInt(t,10);if(isNaN(r))return"";if(r===0)return"영 원 정";const a=["","일","이","삼","사","오","육","칠","팔","구"],d=["","십","백","천"],f=["","만","억","조"];let s="",u=0,e=r;for(;e>0;){const c=e%1e4;if(c>0){let l="",n=c,i=0;for(;n>0;){const o=n%10;if(o>0){const m=o===1&&i>0?"":a[o]+" ",g=i>0?d[i]+" ":"";l=m+g+l}n=Math.floor(n/10),i++}s=`${l}${f[u]} `+s}e=Math.floor(e/1e4),u++}return s.replace(/\s+/g," ").trim()+" 원 정"}export{p as g};
